def calculate_carry_yield(us_rate, jpy_rate, aud_rate, usdjpy_vol, audusd_vol):
    usd_jpy_net_yield = (us_rate - jpy_rate) - 0.02
    aud_usd_net_yield = (aud_rate - us_rate) - 0.02
    risk_adj_usdjpy = usd_jpy_net_yield / usdjpy_vol if usdjpy_vol > 0 else 0
    risk_adj_audusd = aud_usd_net_yield / audusd_vol if audusd_vol > 0 else 0
    return {'USD_JPY_net_yield': usd_jpy_net_yield, 'AUD_USD_net_yield': aud_usd_net_yield, 'USD_JPY_risk_adj': risk_adj_usdjpy, 'AUD_USD_risk_adj': risk_adj_audusd, 'optimal_direction': 'USD/JPY Long' if risk_adj_usdjpy > risk_adj_audusd else 'AUD/USD Long'}

